const { put, get } = require\('@vercel/blob'\);
\(async \(\) => {
  // Write test data
  await put\('tests/test-get.json', JSON.stringify\({test: true}\), {
    access: 'private', contentType: 'application/json',
    addRandomSuffix: false, allowOverwrite: true,
  }\);

  // First read
  const r1 = await get\('tests/test-get.json', { access: 'private' }\);
  console.log\('Read 1 - statusCode:', r1.statusCode\);
  console.log\('Read 1 - stream type:', typeof r1.stream, r1.stream === null ? 'NULL' : 'EXISTS'\);
  console.log\('Read 1 - blob keys:', Object.keys\(r1.blob || {}\)\);
  if \(r1.stream\) {
    const text = await new Response\(r1.stream\).text\(\);
    console.log\('Read 1 - content:', text\);
  }

  // Second read
  const r2 = await get\('tests/test-get.json', { access: 'private' }\);
  console.log\('Read 2 - statusCode:', r2.statusCode\);
  console.log\('Read 2 - stream type:', typeof r2.stream, r2.stream === null ? 'NULL' : 'EXISTS'\);
  if \(r2.stream\) {
    const text = await new Response\(r2.stream\).text\(\);
    console.log\('Read 2 - content:', text\);
  }
}\)\(\);
" 2>&1)
